import header from '../../css/header.module.css';

const Header = () => {
  return (
    <header className={header.header}>
        <h1 className={header.h1}><span className={header.red_text}>Dash</span>board</h1>
        
        <div className={header.searh_bar}> 
            <input className={header.input} type="text" placeholder="Search your task here..."/>
            <button className={'${header.button} ${header.right}'}><img src="/images/icons/search.svg" alt="search"/></button>
        </div>
        
        <button className={header.button}><img src="/images/icons/notification.svg" alt="notification"/></button>
        <button className={header.button}><img src="/images/icons/calender.svg" alt="calendar"/></button>

        <div className={header.date}> 
            <label>Tuesday</label>
            <label><span className={header.blue_text}>20/06/2023</span></label>
        </div>
    </header>
  );
};

export default Header;
